question:
Given the multi-process program below, what is/are the feasible output(s)?
int main()
{
 int a = 2;
 if (fork() == 0){
  if (fork() == 0){
 a++;
  printf("%d ", a);
  exit(1);
  }
 a++;
 printf("%d ", a);
  exit(2);
 }
 a++;
 printf("%d ", a);
 exit(0);
}

