question:
Given the following program, which modification(s) can improve the locality of the program?
#define N 20
int summarize (int a[N][N][N])
{
 int i, j, k;
 int sum = 0;
 for (i = 0; i < N; i++)
 for (j = 0; j < N; j++)
 for (k = 0; k < N; k++)
 sum += a[k][i][j];
}

